#include <iostream>
using namespace std;
class Solution {
public:
    int misleadingcountofleadingones(int n) {
        int i = 1;
        int count = 0;
        while(i <= n and (n & i) == i) {
            i = i << 1;
            count++;
        }
        return count;
    }
};
int main() {
    int t;
    cin >> t;
    while(t--) {
        int n;
        cin >> n;
        cout << Solution().misleadingcountofleadingones(n) << endl;
    }
    return 0;
}
